  input logic start, abort,
  output logic busy
);
  typedef enum logic [1:0] {IDLE, RUNNING, ERROR} state_t;
  state_t state, next_state;

  always_ff @(posedge clk or negedge rst_n)
    if (!rst_n) state <= IDLE;
    else state <= next_state;

  always_comb begin
    next_state = state;
    case (state)
      IDLE: if (start) next_state = RUNNING;
      RUNNING: if (abort) next_state = ERROR;
      ERROR: next_state = IDLE; // Explicit exit from ERROR state
    endcase
  end
  assign busy = (state != IDLE);
endmodule

